+            await load();
+            expect(steps.value[0]?.state).toBe("error");
+        });
+
+        it("is deleted — from deleting populated_state", async () => {
+            const { steps, load } = withJobStates({ ok: 1 }, "deleting");
+            await load();
+            expect(steps.value[0]?.state).toBe("deleted");
+        });
+    });
+});

